export const getActiveReviews = (): Review[] => mockReviews.filter(r => r.isActive && r.moderation?.status === 'approved');
export const getReviewsBySpa = (spaId: string): Review[] =>
  mockReviews.filter(r => r.spaId === spaId && r.isActive && r.moderation?.status === 'approved');
export const getReviewsByTherapist = (therapistId: string): Review[] =>
  mockReviews.filter(r => r.therapistId === therapistId && r.isActive && r.moderation?.status === 'approved');
export const getReviewsByBooking = (bookingId: string): Review[] =>
  mockReviews.filter(r => r.bookingId === bookingId);
export const getPendingReviews = (): Review[] =>
  mockReviews.filter(r => r.moderation?.status === 'pending');
export const getReportedReviews = (): Review[] =>
  mockReviews.filter(r => r.reportedCount > 0);
